<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Falling Sand Sandbox</title>
<style>
  :root {
    color-scheme: dark;
    --bg: #0b0e14;
    --panel: #151b27;
    --panel2: #1d2535;
    --line: #2d3950;
    --text: #eaf2ff;
    --muted: #9aa9c3;
    --accent: #ffcf4a;
  }

  * { box-sizing: border-box; }

  body {
    margin: 0;
    min-height: 100vh;
    display: grid;
    place-items: center;
    background:
      radial-gradient(circle at 50% 0%, #18233a 0%, transparent 42%),
      var(--bg);
    color: var(--text);
    font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
  }

  .app {
    width: min(860px, calc(100vw - 24px));
    text-align: center;
    padding: 22px 0 28px;
  }

  h1 {
    margin: 0 0 6px;
    font-size: clamp(1.45rem, 3vw, 2rem);
    letter-spacing: .04em;
  }

  .subtitle {
    margin: 0 0 16px;
    color: var(--muted);
    font-size: .95rem;
  }

  .toolbar {
    display: flex;
    justify-content: center;
    align-items: center;
    flex-wrap: wrap;
    gap: 9px;
    margin: 0 auto 16px;
  }

  button {
    border: 1px solid var(--line);
    color: var(--text);
    background: linear-gradient(180deg, #263248, #1a2232);
    border-radius: 10px;
    padding: 9px 13px;
    min-width: 94px;
    cursor: pointer;
    font: inherit;
    font-weight: 700;
    box-shadow: 0 3px 0 #080b10, inset 0 1px rgba(255,255,255,.08);
    transition: transform .08s, filter .15s, border-color .15s;
    user-select: none;
  }

  button:hover {
    filter: brightness(1.16);
    border-color: #62799f;
  }

  button:active {
    transform: translateY(2px);
    box-shadow: 0 1px 0 #080b10, inset 0 1px rgba(255,255,255,.08);
  }

  button.selected {
    color: #14110a;
    background: linear-gradient(180deg, #ffe37a, #e8a92d);
    border-color: #ffe99b;
  }

  #clear {
    background: linear-gradient(180deg, #593146, #352031);
    border-color: #7c4961;
  }

  .swatch {
    display: inline-block;
    width: .72em;
    height: .72em;
    margin-right: 7px;
    border-radius: 50%;
    vertical-align: -.04em;
    box-shadow: 0 0 0 1px rgba(255,255,255,.35);
  }

  .sand-dot { background: #e7bd54; }
  .water-dot { background: #36a6ec; }
  .wall-dot { background: #8992a0; }
  .acid-dot { background: #79e650; }
  .empty-dot { background: #171d28; }

  .canvas-wrap {
    display: inline-block;
    padding: 10px;
    border-radius: 16px;
    background: linear-gradient(145deg, #222c3d, #111722);
    border: 1px solid #36455e;
    box-shadow: 0 18px 45px rgba(0,0,0,.45), inset 0 1px rgba(255,255,255,.08);
  }

  #sand {
    display: block;
    width: 720px;
    height: 540px;
    max-width: calc(100vw - 46px);
    background: #0d121b;
    image-rendering: pixelated;
    cursor: crosshair;
    touch-action: none;
    border-radius: 7px;
  }

  .hint {
    margin: 12px 0 0;
    color: var(--muted);
    font-size: .87rem;
  }

  kbd {
    padding: 1px 5px;
    border: 1px solid #43516a;
    border-radius: 4px;
    background: #1b2433;
    color: #d9e8ff;
    font-size: .8rem;
  }
</style>
</head>
<body>
<main class="app">
  <h1>Falling Sand</h1>
  <p class="subtitle">Choose a material, then paint directly onto the sandbox.</p>

  <div class="toolbar" aria-label="Material selector">
    <button id="mat-sand" class="selected" type="button"><span class="swatch sand-dot"></span>Sand</button>
    <button id="mat-water" type="button"><span class="swatch water-dot"></span>Water</button>
    <button id="mat-wall" type="button"><span class="swatch wall-dot"></span>Wall</button>
    <button id="mat-acid" type="button"><span class="swatch acid-dot"></span>Acid</button>
    <button id="mat-empty" type="button"><span class="swatch empty-dot"></span>Eraser</button>
    <button id="clear" type="button">Clear grid</button>
  </div>

  <div class="canvas-wrap">
    <canvas id="sand" width="720" height="540" aria-label="Falling sand simulation canvas"></canvas>
  </div>
  <p class="hint">Drag to paint · Sand sinks through liquid · Acid erodes walls</p>
</main>

<script>
(() => {
  "use strict";

  const canvas = document.getElementById("sand");
  const ctx = canvas.getContext("2d", { alpha: false });

  const w = 120;
  const h = 90;
  const cellSize = 6;

  const EMPTY = 0;
  const SAND = 1;
  const WATER = 2;
  const WALL = 3;
  const ACID = 4;

  const names = ["empty", "sand", "water", "wall", "acid"];
  const ids = {
    empty: EMPTY,
    sand: SAND,
    water: WATER,
    wall: WALL,
    acid: ACID
  };

  const colors = [
    "#0d121b",
    "#e7bd54",
    "#35a9ef",
    "#848d9d",
    "#78e850"
  ];

  const grid = new Uint8Array(w * h);
  const moved = new Int32Array(w * h);
  let stepNumber = 0;
  let randomState = 0x6d2b79f5;
  let selected = "sand";
  let painting = false;

  function index(x, y) {
    return y * w + x;
  }

  function inside(x, y) {
    return x >= 0 && x < w && y >= 0 && y < h;
  }

  function randomBit() {
    randomState ^= randomState << 13;
    randomState ^= randomState >>> 17;
    randomState ^= randomState << 5;
    randomState >>>= 0;
    return randomState & 1;
  }

  function getCell(x, y) {
    if (!inside(x, y)) return "empty";
    return names[grid[index(x, y)]];
  }

  function setCell(x, y, material) {
    x = Math.floor(Number(x));
    y = Math.floor(Number(y));
    if (!inside(x, y) || !(material in ids)) return;
    grid[index(x, y)] = ids[material];
    render();
  }

  function clearGrid() {
    grid.fill(EMPTY);
    moved.fill(0);
    stepNumber = 0;
    randomState = 0x6d2b79f5;
    render();
  }

  function markMoved(x, y) {
    moved[index(x, y)] = stepNumber;
  }

  function wasMoved(x, y) {
    return moved[index(x, y)] === stepNumber;
  }

  function moveCell(x, y, nx, ny) {
    const from = index(x, y);
    const to = index(nx, ny);
    grid[to] = grid[from];
    grid[from] = EMPTY;
    moved[from] = stepNumber;
    moved[to] = stepNumber;
  }

  /*
    Sand's liquid displacement prefers a neighboring escape route rather than
    continuously carrying water upward through a vertical stream of sand.
  */
  function sinkIntoLiquid(x, y, liquidY) {
    const liquid = grid[index(x, liquidY)];
    const first = randomBit() ? -1 : 1;
    const dirs = [first, -first];

    for (const dx of dirs) {
      const sx = x + dx;
      if (sx >= 0 && sx < w && grid[index(sx, liquidY)] === EMPTY) {
        grid[index(sx, liquidY)] = liquid;
        grid[index(x, liquidY)] = SAND;
        grid[index(x, y)] = EMPTY;
        markMoved(x, y);
        markMoved(x, liquidY);
        markMoved(sx, liquidY);
        return true;
      }
    }

    for (const dx of dirs) {
      const sx = x + dx;
      if (sx >= 0 && sx < w && grid[index(sx, y)] === EMPTY) {
        grid[index(sx, y)] = liquid;
        grid[index(x, liquidY)] = SAND;
        grid[index(x, y)] = EMPTY;
        markMoved(x, y);
        markMoved(x, liquidY);
        markMoved(sx, y);
        return true;
      }
    }

    return false;
  }

  function updateSand(x, y) {
    if (y < h - 1) {
      const below = grid[index(x, y + 1)];

      if (below === EMPTY) {
        moveCell(x, y, x, y + 1);
        return;
      }

      if (below === WATER || below === ACID) {
        if (sinkIntoLiquid(x, y, y + 1)) return;
      }

      const first = randomBit() ? -1 : 1;
      for (const dx of [first, -first]) {
        const nx = x + dx;
        const ny = y + 1;
        if (nx >= 0 && nx < w && grid[index(nx, ny)] === EMPTY) {
          moveCell(x, y, nx, ny);
          return;
        }
      }
    }
    markMoved(x, y);
  }

  function dissolveWithAcid(x, y) {
    const first = randomBit() ? -1 : 1;
    const targets = [
      [x, y + 1],
      [x + first, y],
      [x - first, y]
    ];

    for (const [tx, ty] of targets) {
      if (!inside(tx, ty)) continue;
      const target = grid[index(tx, ty)];
      if (target === SAND || target === WALL) {
        grid[index(tx, ty)] = EMPTY;
        markMoved(x, y);
        markMoved(tx, ty);
        return true;
      }
    }
    return false;
  }

  function updateLiquid(x, y, material) {
    if (material === ACID && dissolveWithAcid(x, y)) return;

    if (y < h - 1 && grid[index(x, y + 1)] === EMPTY) {
      moveCell(x, y, x, y + 1);
      return;
    }

    const first = randomBit() ? -1 : 1;
    for (const dx of [first, -first]) {
      const nx = x + dx;
      if (nx >= 0 && nx < w && grid[index(nx, y)] === EMPTY) {
        moveCell(x, y, nx, y);
        return;
      }
    }

    markMoved(x, y);
  }

  function step() {
    stepNumber++;
    if (stepNumber === 2147483647) {
      moved.fill(0);
      stepNumber = 1;
    }

    for (let y = h - 1; y >= 0; y--) {
      for (let x = 0; x < w; x++) {
        const i = index(x, y);
        if (moved[i] === stepNumber) continue;

        const material = grid[i];
        if (material === SAND) {
          updateSand(x, y);
        } else if (material === WATER || material === ACID) {
          updateLiquid(x, y, material);
        }
      }
    }
  }

  function tick(n) {
    n = Math.max(0, Math.floor(Number(n) || 0));
    for (let i = 0; i < n; i++) step();
    render();
  }

  function render() {
    ctx.fillStyle = colors[EMPTY];
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    for (let y = 0; y < h; y++) {
      for (let x = 0; x < w; x++) {
        const material = grid[index(x, y)];
        if (material !== EMPTY) {
          ctx.fillStyle = colors[material];
          ctx.fillRect(x * cellSize, y * cellSize, cellSize, cellSize);
        }
      }
    }

    ctx.fillStyle = "rgba(255,255,255,.025)";
    for (let x = 0; x <= w; x += 10) {
      ctx.fillRect(x * cellSize, 0, 1, canvas.height);
    }
    for (let y = 0; y <= h; y += 10) {
      ctx.fillRect(0, y * cellSize, canvas.width, 1);
    }
  }

  function paintAt(event) {
    const rect = canvas.getBoundingClientRect();
    const x = Math.floor((event.clientX - rect.left) * w / rect.width);
    const y = Math.floor((event.clientY - rect.top) * h / rect.height);
    const material = ids[selected];

    for (let oy = -1; oy <= 1; oy++) {
      for (let ox = -1; ox <= 1; ox++) {
        if (ox * ox + oy * oy > 2) continue;
        const px = x + ox;
        const py = y + oy;
        if (inside(px, py)) grid[index(px, py)] = material;
      }
    }
    render();
  }

  canvas.addEventListener("pointerdown", event => {
    painting = true;
    canvas.setPointerCapture(event.pointerId);
    paintAt(event);
  });

  canvas.addEventListener("pointermove", event => {
    if (painting) paintAt(event);
  });

  canvas.addEventListener("pointerup", () => { painting = false; });
  canvas.addEventListener("pointercancel", () => { painting = false; });
  canvas.addEventListener("contextmenu", event => event.preventDefault());

  for (const material of Object.keys(ids)) {
    const button = document.getElementById("mat-" + material);
    button.addEventListener("click", () => {
      selected = material;
      document.querySelectorAll(".toolbar button[id^='mat-']").forEach(b => {
        b.classList.toggle("selected", b.id === "mat-" + material);
      });
    });
  }

  document.getElementById("clear").addEventListener("click", clearGrid);

  window.sim = {
    w,
    h,
    tick,
    get: getCell,
    set: setCell,
    clear: clearGrid
  };

  render();

  let lastFrame = 0;
  function animate(time) {
    if (time - lastFrame >= 42) {
      step();
      render();
      lastFrame = time;
    }
    requestAnimationFrame(animate);
  }
  requestAnimationFrame(animate);
})();
</script>
</body>
</html>
